// WF1 v8.2 - Extract & Filter với Email Limiting
// Form CŨ: 1cqQQ6i_flcil5msjouFvvqBIETqyV0Ukcf2Ysrqsth4

const results = $input.first().json.results || [];
const today = new Date().toISOString().split('T')[0];

const eligibleItems = [];
const skippedItems = [];
const needsHrLookup = [];
const directEmail = [];

for (const page of results) {
  const props = page.properties;

  // Basic info
  const id = page.id;
  const tieuDe = props['Tiêu đề']?.title?.[0]?.plain_text || 'Không có tiêu đề';

  // Email limiting - check số lần gửi và ngày gửi
  const soLanGui = props['📧 Số lần gửi']?.number || 0;
  const ngayGuiRaw = props['📅 Ngày gửi gần nhất']?.date?.start || null;
  const ngayGuiGanNhat = ngayGuiRaw ? ngayGuiRaw.split('T')[0] : null;

  // Check if can send today
  const isToday = ngayGuiGanNhat === today;
  const canSend = !isToday || soLanGui < 2;

  if (!canSend) {
    skippedItems.push({
      id,
      title: tieuDe,
      reason: `Đã gửi ${soLanGui} lần hôm nay (${today})`
    });
    continue;
  }

  // Extract all properties for prefill
  const nguon = props['Nguồn']?.select?.name || '';
  const ngayNhan = props['Ngày nhận']?.date?.start || '';
  const noiDungGoc = props['Nội dung gốc']?.rich_text?.[0]?.plain_text || '';
  const t2NhiemVu = props['T2 - NHIỆM VỤ']?.rich_text?.[0]?.plain_text || '';
  const t3ChiTieu = props['T3 - CHỈ TIÊU']?.rich_text?.[0]?.plain_text || '';
  const t4ThoiHan = props['T4 - THỜI HẠN']?.date?.start || '';
  const ghiChu = props['Ghi chú']?.rich_text?.[0]?.plain_text || '';

  // Email resolution
  const emailDauMoi = props['📧 Email đầu mối']?.email || '';
  const hrRelation = props['👤 Người nhận chỉ đạo (HR)']?.relation || [];
  const hrId = hrRelation.length > 0 ? hrRelation[0].id : null;

  const item = {
    id,
    tieuDe,
    nguon,
    ngayNhan,
    noiDungGoc,
    t2NhiemVu,
    t3ChiTieu,
    t4ThoiHan,
    ghiChu,
    emailDauMoi,
    hrId,
    soLanGui,
    newSoLanGui: isToday ? soLanGui + 1 : 1,
    todayDate: today
  };

  eligibleItems.push(item);

  // Categorize by email source
  if (emailDauMoi) {
    directEmail.push(item);
  } else if (hrId) {
    needsHrLookup.push(item);
  } else {
    // Use fallback
    item.resolvedEmail = 'vynnl@esuhai.com';
    item.resolvedName = 'HR Vy (Fallback)';
    item.usedFallback = true;
    directEmail.push(item);
  }
}

console.log(`[WF1 v8.2] Total: ${results.length}, Eligible: ${eligibleItems.length}, Skipped: ${skippedItems.length}`);
console.log(`[WF1 v8.2] Direct email: ${directEmail.length}, Needs HR lookup: ${needsHrLookup.length}`);
if (skippedItems.length > 0) {
  console.log('[WF1 v8.2] Skipped items:', JSON.stringify(skippedItems, null, 2));
}

return {
  eligibleItems,
  skippedItems,
  needsHrLookup,
  directEmail,
  stats: {
    total: results.length,
    eligible: eligibleItems.length,
    skipped: skippedItems.length,
    directEmail: directEmail.length,
    needsHrLookup: needsHrLookup.length
  }
};

// Get unique HR IDs to lookup
const needsHrLookup = $input.first().json.needsHrLookup || [];
const hrIds = [...new Set(needsHrLookup.map(item => item.hrId).filter(Boolean))];

return hrIds.map(id => ({ hrId: id }));

// Combine HR lookup results with items
const hrResults = $input.all().map(item => item.json);
const originalData = $('🔧 Extract & Filter').first().json;

// Build HR lookup map
const hrMap = {};
for (const hr of hrResults) {
  if (hr.id) {
    const props = hr.properties || {};
    hrMap[hr.id] = {
      name: props['Họ và tên']?.title?.[0]?.plain_text || 
            props['Tên']?.title?.[0]?.plain_text || 
            'Không có tên',
      email: props['Email']?.email || 
             props['📧 Email']?.email || ''
    };
  }
}

// Merge needsHrLookup with HR data
const needsHrLookup = originalData.needsHrLookup || [];
const resolvedFromHr = [];

for (const item of needsHrLookup) {
  const hrData = hrMap[item.hrId];
  if (hrData && hrData.email) {
    item.resolvedEmail = hrData.email;
    item.resolvedName = hrData.name;
    item.usedFallback = false;
  } else {
    // Fallback if HR has no email
    item.resolvedEmail = 'vynnl@esuhai.com';
    item.resolvedName = hrData?.name || 'HR Vy (Fallback)';
    item.usedFallback = true;
  }
  resolvedFromHr.push(item);
}

// Combine with directEmail items
const directEmail = originalData.directEmail || [];
for (const item of directEmail) {
  if (!item.resolvedEmail) {
    item.resolvedEmail = item.emailDauMoi;
    item.resolvedName = '';
    item.usedFallback = false;
  }
}

const allItems = [...directEmail, ...resolvedFromHr];

console.log(`[WF1 v8.2] Combined ${allItems.length} items for email`);

return { allItems, hrMap };

// No HR lookup needed - use direct email items
const originalData = $input.first().json;
const directEmail = originalData.directEmail || [];

for (const item of directEmail) {
  if (!item.resolvedEmail) {
    item.resolvedEmail = item.emailDauMoi || 'vynnl@esuhai.com';
    item.resolvedName = '';
    item.usedFallback = !item.emailDauMoi;
  }
}

console.log(`[WF1 v8.2] Direct path: ${directEmail.length} items`);

return { allItems: directEmail };

// Merge from both paths
const items = $input.all().flatMap(i => i.json.allItems || []);
console.log(`[WF1 v8.2] Merged ${items.length} items for processing`);
return items.map(item => ({ json: item }));

// WF1 v8.2 - Build Prefill URL cho Form CŨ
// Form ID: 1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw

const item = $input.first().json;

// Entry IDs cho Form CŨ (đã verify)
const entryIds = {
  maClarification: '1684171280',   // Mã Clarification
  nguonChiDao: '1878008034',       // Nguồn chỉ đạo
  ngayNhanChiDao: '1953342780',    // Ngày nhận chỉ đạo
  noiDungGoc: '1839616630',        // Nội dung chỉ đạo gốc
  dauMoiT1: '649583359',           // Đầu mối thực hiện (T1)
  t2NhiemVu: '1319518938',         // T2 - Nhiệm vụ
  t3ChiTieu: '1910876946',         // T3 - Chỉ tiêu
  t4ThoiHan: '1661283634',         // T4 - Thời hạn (Deadline)
  ghiChu: '1985703119',            // Ghi chú
  xacNhan: '429936070'             // Xác nhận (checkbox - không prefill)
};

// Build form URL
const formId = '1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw';
const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform?usp=pp_url`;

// Build prefill params
const params = [
  `entry.${entryIds.maClarification}=${encodeURIComponent(item.id || '')}`,
  `entry.${entryIds.nguonChiDao}=${encodeURIComponent(item.nguon || '')}`,
  `entry.${entryIds.ngayNhanChiDao}=${encodeURIComponent(item.ngayNhan || '')}`,
  `entry.${entryIds.noiDungGoc}=${encodeURIComponent(item.noiDungGoc || '')}`,
  `entry.${entryIds.dauMoiT1}=${encodeURIComponent(item.resolvedName || '')}`,
  `entry.${entryIds.t2NhiemVu}=${encodeURIComponent(item.t2NhiemVu || '')}`,
  `entry.${entryIds.t3ChiTieu}=${encodeURIComponent(item.t3ChiTieu || '')}`,
  `entry.${entryIds.t4ThoiHan}=${encodeURIComponent(item.t4ThoiHan || '')}`,
  `entry.${entryIds.ghiChu}=${encodeURIComponent(item.ghiChu || '')}`
].join('&');

const prefillUrl = `${baseUrl}&${params}`;

// Build email content
const lanGui = item.newSoLanGui || 1;
const subjectPrefix = `[Lần ${lanGui}]`;
const greeting = item.resolvedName ? `Chào ${item.resolvedName},` : 'Chào Anh/Chị,';

const emailSubject = `${subjectPrefix} Yêu cầu xác nhận chỉ đạo: ${item.tieuDe}`;

const emailBody = `${greeting}

Bạn nhận được yêu cầu xác nhận nhận chỉ đạo từ hệ thống CEO Directive.

📋 **Thông tin chỉ đạo:**
- Tiêu đề: ${item.tieuDe}
- Nguồn: ${item.nguon || 'Chưa xác định'}
- Ngày nhận: ${item.ngayNhan || 'Chưa xác định'}
- Nội dung: ${item.noiDungGoc || 'Xem chi tiết trong form'}

🔗 **Vui lòng xác nhận tại đây:**
${prefillUrl}

⚠️ Lưu ý:
- Vui lòng kiểm tra thông tin đã điền sẵn
- Bổ sung các thông tin còn thiếu (T2, T3, T4 nếu có)
- Tick xác nhận và gửi form

Trân trọng,
Hệ thống CEO Directive - EsuhaiGroup`;

return {
  ...item,
  prefillUrl,
  emailSubject,
  emailBody,
  emailTo: item.resolvedEmail,
  emailCc: 'hoangkha@esuhai.com'
};

